import React, { useState, useEffect, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { doctorAPI, appointmentAPI } from '../services/api';
import { getErrorMessage } from '../utils/helpers';
import DoctorCard from '../components/DoctorCard';
import AppointmentCard from '../components/AppointmentCard';
import './DashboardPages.css';

const PatientPage = ({ showToast }) => {
  const [doctors, setDoctors] = useState([]);
  const [appointments, setAppointments] = useState([]);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState('doctors');
  const [viewingDoctorId, setViewingDoctorId] = useState(null);
  const [bookingData, setBookingData] = useState({
    doctor_id: '',
    date: '',
    time: '',
  });
  const { user, logout } = useContext(AuthContext);
  const navigate = useNavigate();

  useEffect(() => {
    loadDoctors();
    loadAppointments();
  }, []);

  const loadDoctors = async () => {
    setLoading(true);
    try {
      const data = await doctorAPI.getAll();
      setDoctors(data);
    } catch (error) {
      showToast(getErrorMessage(error), 'error');
    } finally {
      setLoading(false);
    }
  };

  const loadAppointments = async () => {
    try {
      const data = await appointmentAPI.getAll();
      setAppointments(data.appointments || []);
    } catch (error) {
      console.error(error);
    }
  };

  const handleBooking = async (e) => {
    e.preventDefault();
    if (!bookingData.doctor_id || !bookingData.date || !bookingData.time) {
      showToast('Please fill in all fields', 'error');
      return;
    }

    try {
      await appointmentAPI.book({
        doctor_id: parseInt(bookingData.doctor_id),
        date: bookingData.date,
        time: bookingData.time,
      });
      showToast('Appointment booked successfully!', 'success');
      setBookingData({ doctor_id: '', date: '', time: '' });
      setViewingDoctorId(null);
      loadAppointments();
    } catch (error) {
      showToast(getErrorMessage(error), 'error');
    }
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <div className="dashboard-page">
      <header className="header">
        <div className="header-content">
          <h1>Patient Dashboard</h1>
          <div className="header-right">
            <div className="user-info">
              Logged in as <strong>{user?.name}</strong> ({user?.role})
            </div>
            <button className="logout-btn" onClick={handleLogout}>
              Logout
            </button>
          </div>
        </div>
      </header>

      <div className="container">
        <div className="page-content">
          <div className="tabs">
            <button
              className={`tab-btn ${activeTab === 'doctors' ? 'active' : ''}`}
              onClick={() => setActiveTab('doctors')}
            >
              Find Doctors ({doctors.length})
            </button>
            <button
              className={`tab-btn ${activeTab === 'appointments' ? 'active' : ''}`}
              onClick={() => setActiveTab('appointments')}
            >
              My Appointments ({appointments.length})
            </button>
          </div>

          {activeTab === 'doctors' && (
            <div className="section">
              <h2>Find & Book Doctors</h2>

              {viewingDoctorId !== null && (
                <div className="booking-form-section">
                  <h3>Book Appointment</h3>
                  <form onSubmit={handleBooking}>
                    <div className="form-group">
                      <label htmlFor="doctor_id">Doctor</label>
                      <select
                        id="doctor_id"
                        value={bookingData.doctor_id}
                        onChange={(e) =>
                          setBookingData({ ...bookingData, doctor_id: e.target.value })
                        }
                      >
                        <option value="">Select a doctor</option>
                        {doctors.map((doctor) => (
                          <option key={doctor.id} value={doctor.id}>
                            {doctor.name} - {doctor.specialization}
                          </option>
                        ))}
                      </select>
                    </div>

                    <div className="form-group">
                      <label htmlFor="date">Date</label>
                      <input
                        id="date"
                        type="date"
                        value={bookingData.date}
                        onChange={(e) =>
                          setBookingData({ ...bookingData, date: e.target.value })
                        }
                      />
                    </div>

                    <div className="form-group">
                      <label htmlFor="time">Time</label>
                      <input
                        id="time"
                        type="time"
                        value={bookingData.time}
                        onChange={(e) =>
                          setBookingData({ ...bookingData, time: e.target.value })
                        }
                      />
                    </div>

                    <div className="button-group">
                      <button type="submit" className="btn-primary">
                        Book Appointment
                      </button>
                      <button
                        type="button"
                        className="btn-secondary"
                        onClick={() => setViewingDoctorId(null)}
                      >
                        Cancel
                      </button>
                    </div>
                  </form>
                </div>
              )}

              {loading ? (
                <div className="loading">Loading doctors...</div>
              ) : doctors.length === 0 ? (
                <div className="no-data">No approved doctors available</div>
              ) : (
                <div className="doctors-list">
                  {doctors.map((doctor) => (
                    <div key={doctor.id} className="doctor-item">
                      <DoctorCard doctor={doctor} />
                      <button
                        className="btn-primary"
                        onClick={() => {
                          setViewingDoctorId(doctor.id);
                          setBookingData({ ...bookingData, doctor_id: doctor.id.toString() });
                        }}
                      >
                        Book Appointment
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'appointments' && (
            <div className="section">
              <h2>My Appointments</h2>
              {appointments.length === 0 ? (
                <div className="no-data">No appointments yet</div>
              ) : (
                <div className="appointments-list">
                  {appointments.map((appointment) => (
                    <AppointmentCard
                      key={appointment.id}
                      appointment={appointment}
                      userRole="patient"
                    />
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default PatientPage;
